// Logo en base64 (data URI) listo para usar en <img>
// Uso:  <img src="" id="logo">  ->  document.getElementById('logo').src = LOGO_BASE64;
//   o:  <img src="" onload="this.src=LOGO_BASE64">
// ==========================================================

const LOGO_BASE64 = "data:image/png;base64,";

// Alias de compatibilidad (por si el sistema usa otro nombre)
window.LOGO_BASE64 = LOGO_BASE64;
window.LOGO = LOGO_BASE64;
if (typeof module !== 'undefined' && module.exports) { module.exports = LOGO_BASE64; }

// Alias requerido por el sistema POS (Parte 8)
window.LOGO_DEFAULT = LOGO_BASE64;
